# Faithful transliteration of validateWheelArgs from hamster_wheel.js (LOGIC PROXY ONLY;
# no node/bun on the box). Mirrors the exact predicate to exercise the failure paths.
import json
REQUIRED = ['wheel','worktree','branch','focus','progress_file']
UNDEFINED = object()  # stand-in for JS `undefined`

def validate(raw):
    a = raw
    if isinstance(a, str):
        try: a = json.loads(a)
        except Exception as e:
            return {'ok': False, 'missing': list(REQUIRED), 'reason': f'args is a non-JSON string: {e}'}
    if a is None or a is UNDEFINED or not isinstance(a, dict):
        kind = 'null' if (a is None or a is UNDEFINED) else type(a).__name__
        return {'ok': False, 'missing': list(REQUIRED), 'reason': f'args is {kind}, expected an object'}
    missing = []
    for k in REQUIRED:
        v = a.get(k, UNDEFINED)
        if not isinstance(v, str) or v.strip() == '' or v in ('undefined','null'):
            missing.append(k)
    return {'ok': len(missing) == 0, 'missing': missing, 'args': a}

def show(label, raw):
    r = validate(raw)
    if not r['ok']:
        detail = f" ({r['reason']})" if r.get('reason') else ''
        print(f"{label:38} -> FATAL missing=[{', '.join(r['missing'])}]{detail}  (RETURN, 0 agents spawned)")
    else:
        print(f"{label:38} -> OK, proceed as wheel '{r['args']['wheel']}'")

# The exact regression + edge inputs:
show('undefined (the actual bug)', UNDEFINED)
show('None', None)
show('{} empty object', {})
show('all keys literal "undefined"', {k:'undefined' for k in REQUIRED})
show('missing branch+progress_file', {'wheel':'outline','worktree':'/home/polaris/wt/outline_agent','focus':'x'})
show('empty-string worktree', {'wheel':'o','worktree':'  ','branch':'b','focus':'f','progress_file':'p'})
show('non-JSON string', 'not json {')
show('valid JSON string', json.dumps({'wheel':'outline','worktree':'/home/polaris/wt/outline_agent','branch':'bot/outline-agent-box','focus':'f','progress_file':'wheel_outline.md'}))
show('fully valid object', {'wheel':'compose','worktree':'/home/polaris/wt/compose','branch':'bot/compose-box','focus':'f','progress_file':'wheel_compose.md'})
